-- Enkelt-fil: seeder KUN den nye pre-game-raden (elfenbenskysten-norge).
-- Rorer ingen andre quizer. Kjor i Supabase -> SQL Editor.
-- Status = open => kortet er live i vm.html med en gang.

insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'pregame-elfenbenskysten-norge', '15', 'Pre-game',
  'Før kampen: Elfenbenskysten–Norge', '16-delsfinale i Dallas — Norges første utslagskamp på 28 år. Ta den før avspark.', 'vm-gruppespill-1', 'medium',
  '[{"category": "Sluttspill", "q": "Hva står på spill når Norge møter Elfenbenskysten i 16-delsfinalen 30. juni?", "options": ["Begge lag er allerede videre uansett", "Det avgjør kun gruppeseieren", "Det er utslagsspill — taperen er ute av VM, vinneren går videre til åttedelsfinalen", "Taperen havner i en ekstra omspillsrunde"], "correct": 2, "explanation": "16-delsfinalen er ren utslagsrunde og Norges første sluttspillkamp siden 1998. Vinneren går videre til åttedelsfinalen (mot vinneren av Brasil–Japan); taperen er ute av VM."}, {"category": "Elfenbenskysten", "q": "Hva er kallenavnet til Elfenbenskystens landslag?", "options": ["Ørnene", "Elefantene", "Pantrene", "Løvene"], "correct": 1, "explanation": "Elfenbenskysten kalles «Elefantene» (Les Éléphants) — elefanten er et nasjonalsymbol for landet."}, {"category": "Elfenbenskysten", "q": "Elfenbenskysten vant Afrikamesterskapet (AFCON) på hjemmebane for et par år siden. Hvem slo de i finalen?", "options": ["Senegal", "Egypt", "Nigeria", "Marokko"], "correct": 2, "explanation": "Elfenbenskysten arrangerte og vant AFCON (spilt i 2024) med 2–1 over Nigeria i finalen i Abidjan. Den regjerende afrikamesteren er nå Marokko, som vant AFCON 2025."}, {"category": "Elfenbenskysten", "q": "Hvem er Elfenbenskystens mestscorende landslagsspiller gjennom tidene?", "options": ["Didier Drogba", "Salomon Kalou", "Wilfried Zaha", "Yaya Touré"], "correct": 0, "explanation": "Klubblegenden Didier Drogba scoret 65 mål for Elfenbenskysten og er landets store ikon."}, {"category": "Elfenbenskysten", "q": "Hvilken Manchester United-spiller scoret Elfenbenskystens sene vinnermål i åpningskampen mot Ecuador?", "options": ["Wilfried Zaha", "Sébastien Haller", "Amad Diallo", "Simon Adingra"], "correct": 2, "explanation": "Amad Diallo avgjorde 1–0 mot Ecuador helt på tampen — en nøkkelseier på veien til utslagsspillet."}, {"category": "Norge", "q": "Hvorfor er det historisk at Norge i det hele tatt spiller denne 16-delsfinalen?", "options": ["Det er første gang Norge spiller utenfor Europa", "Det er Norges første VM-sluttspillkamp siden 1998", "Det er Norges aller første VM noensinne", "Norge er regjerende verdensmester"], "correct": 1, "explanation": "Norge er tilbake i et herre-VM etter 28 år, og en utslagskamp er ny grunn for de fleste på dagens lag."}, {"category": "Haaland", "q": "Hvor mange mål scoret Erling Haaland i gruppespillet i VM 2026?", "options": ["Fire", "To", "Seks", "Ett"], "correct": 0, "explanation": "Haaland scoret to mot Irak og to mot Senegal — fire mål i gruppespillet på sin VM-debut."}, {"category": "Norge", "q": "Hvordan tok Norge seg videre fra gruppe I til 16-delsfinalen?", "options": ["Som gruppevinner foran Frankrike", "Som en av de beste treerne", "Som nummer to bak Frankrike — seire over Irak og Senegal, tap mot Frankrike", "Via omspill mot Senegal"], "correct": 2, "explanation": "Norge slo Irak 4–1 og Senegal 3–2, men tapte 1–4 for Frankrike i siste kamp og endte nummer to i gruppe I."}, {"category": "Elfenbenskysten", "q": "Hvordan kom Elfenbenskysten seg til 16-delsfinalen?", "options": ["Ved å vinne alle tre kampene", "Som nummer to i gruppe E, bak Tyskland", "Som en av de beste treerne", "Som gruppevinner foran Tyskland"], "correct": 1, "explanation": "Elfenbenskysten endte nummer to i gruppe E med seks poeng, bak Tyskland og foran Ecuador."}, {"category": "Elfenbenskysten", "q": "Hva er spesielt med at Elfenbenskysten i det hele tatt er i 16-delsfinalen?", "options": ["Det er deres første VM noensinne", "De har vunnet gruppespillet i alle sine VM", "Det er deres aller første VM-utslagskamp — de har aldri kommet forbi gruppespillet før", "De er regjerende verdensmester"], "correct": 2, "explanation": "Tross fire VM-deltakelser (2006, 2010, 2014, 2026) hadde Elfenbenskysten aldri tatt seg videre fra gruppespillet før nå."}]'::jsonb, 'open', 15, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;
